// 📦 CONTEXT INJECTOR — pega esto en los 4 clusters
const agentOutput = $input.first().json;
const trigger = $('When Executed by Another Workflow').first().json;

return [{
  json: {
    // ─── OUTPUT DEL AGENTE ───
    output: agentOutput.output || agentOutput.text || agentOutput.response || '',

    // ─── CONTEXTO ORIGINAL COMPLETO ───
    channel: trigger.channel || 'telegram',

    // ─── TELEGRAM ───
    message: trigger.message || null,
    callback_query: trigger.callback_query || null,

    // ─── WHATSAPP ───
    remoteJid: trigger.remoteJid || null,
    messageId: trigger.messageId || null,

    // ─── SESSION ───
    _sessionId: trigger._sessionId || trigger.message?.chat?.id?.toString() || trigger.chatId || 'fallback_session',
    chatId: trigger.message?.chat?.id || trigger.callback_query?.message?.chat?.id || trigger.chatId || '',

    // ─── CLUSTER INFO ───
    _cluster: trigger._cluster || 'UNKNOWN',
    _isCallback: trigger._isCallback || false,
  }
}];
